#include <string>
#include <vector>
#include <algorithm>

class Solution {
public:
    string reformatNumber(string number) {
        string reformattedNumber;
        vector<int> digits;

        for (char c : number) {
            if (isdigit(c)) {
                digits.push_back(c - '0');
            } else {
                reformattedNumber += c;
            }
        }

        sort(digits.begin(), digits.end());

        int n = digits.size();
        int m = digits[n-1] - digits[0];

        for (int i = n-1; i >= 0; i--) {
            if (i + m <= n) {
                digits[i] = digits[i] + digits[i+m];
            } else {
                digits[i] = digits[i];
            }
        }

        for (int i = 0; i < n; i++) {
            if (i + m <= n) {
                digits[i] = digits[i] + digits[i+m];
            } else {
                digits[i] = digits[i];
            }
        }

        return reformattedNumber;
    }
};
